class Solution {
    public boolean uniqueOccurrences(int[] arr) {
        int[] count = new int[2001];
        for (int num : arr) {
            count[num + 1000]++;
        }
        boolean[] seen = new boolean[arr.length + 1];
        for (int i = 0; i < count.length; i++) {
            if (count[i] > 0) {
                if (seen[count[i]]) {
                    return false;
                }
                seen[count[i]] = true;
            }
        }
        return true;
    }
}
